function orientPrimitiveGroup(
  group: THREE.Group,
  primitive: FloraPrimitiveName,
  point: THREE.Vector3,
  theta: number,
  rng: ReturnType<typeof createRng>,
  placement: FlowerPlanItem['placement'] = 'mixed'
) {
  const outward = point.clone().setY(point.y * 0.55 + 0.48).normalize();
  const facePrimitives: FloraPrimitiveName[] = [
    'CosmosOpenFlower',
    'DiskFlower',
    'LayeredDahliaFlower',
    'RuffledRoseFlower',
    'StarPinwheelFlower',
    'TrumpetThroatFlower',
    'DaturaTrumpetFlower',
    'OrchidButterflyFlower'
  ];

  if (facePrimitives.includes(primitive)) {
    group.quaternion.setFromUnitVectors(forward, outward.lengthSq() ? outward : forward);
    group.rotateZ(rng.range(0, Math.PI * 2));
    group.rotateX(rng.range(-0.18, 0.18));
    return;
  }

  if (primitive === 'SpikeFlower') {
    const [minLean, maxLean] = spikeLeanRange(placement);
    const target = point.clone().sub(bouquetTiePoint).normalize();
    const tangent = new THREE.Vector3(-target.z, 0, target.x).normalize();
    const leanVariation = rng.range(minLean, maxLean) * rng.range(-0.28, 0.28);
    target.addScaledVector(tangent, leanVariation).normalize();
    group.quaternion.setFromUnitVectors(up, target);
    group.rotateY(rng.range(-Math.PI, Math.PI));
    return;
  }

  if (primitive === 'FoliageGrassBranch') {
    group.quaternion.setFromUnitVectors(up, new THREE.Vector3(Math.cos(theta) * 0.22, 1, Math.sin(theta) * 0.22).normalize());
    group.rotateY(rng.range(-0.45, 0.45));
    return;
  }

  if (primitive === 'HangingBellFruit') {
    group.rotation.set(rng.range(-0.18, 0.18), theta + rng.range(-0.35, 0.35), rng.range(-0.12, 0.12));
    return;
  }

  group.quaternion.setFromUnitVectors(up, outward.lengthSq() ? outward : up);
  group.rotateY(rng.range(0, Math.PI * 2));
}

function buildPrimitiveFlowers(spec: DailyBouquetSpec, quality: QualityProfile) {
  const plannedCount = Math.floor(quality.flowerCount * spec.flowerDensity);
  const specialPrimitiveRatio = spec.flowerPlan.id === 'her-real-bouquet-memory-v4' ? 0.5 : 0.34;
  const count = Math.max(64, Math.floor(plannedCount * (spec.special ? specialPrimitiveRatio : 0.34)));
  const group = new THREE.Group();
  const batches = spec.flowerPlan.items;
  const roleShares = spec.compositionTuning?.roleShare;
  const weightedShares = batches.map((batch) => batch.share * (roleShares?.[batch.role] ?? 1));
  const shareTotal = weightedShares.reduce((sum, share) => sum + share, 0) || 1;
  const flowerRecords: FlowerAuditRecord[] = [];
  const stems: PlantStemInstance[] = [];
  const leaves: LeafInstanceRecord[] = [];
  let used = 0;

  batches.forEach((batch, index) => {
    const adjustedShare = weightedShares[index] / shareTotal;
    const batchCount = index === batches.length - 1 ? count - used : Math.max(1, Math.floor(count * adjustedShare));
    used += batchCount;
    const primitive = primitiveForPlanItem(batch, spec.flowerPlan.id);
    const factory = floraPrimitiveFactories[primitive];
    const localRng = createRng(`${spec.seed}:primitive-flowers:${spec.flowerPlan.id}:${batch.typeId}:${primitive}`);

    for (let i = 0; i < batchCount; i += 1) {
      const { p, theta } = placementPoint(spec, localRng, batch.placement);
      if (primitive === 'SpikeFlower') {
        settleSpikeAnchor(p, batch.placement, localRng);
        p.y += spec.compositionTuning?.spikeAnchorLift ?? 0;
      }
      const roleScale =
        batch.role === 'main' ? 0.26 :
        batch.role === 'line' ? 0.25 :
        batch.role === 'cluster' ? 0.23 :
        batch.role === 'fruit' ? 0.2 :
        batch.role === 'filler' ? 0.16 :
        0.21;
      const bloom = spec.special?.bloomScale;
      const specialScale = bloom ? localRng.range(bloom.small, bloom.medium) * 0.52 : 1;
      const tuningScale = spec.compositionTuning?.roleScale?.[batch.role] ?? 1;
      const spikeScale = primitive === 'SpikeFlower' ? spec.compositionTuning?.spikeScale ?? 1 : 1;
      const primitiveGroup = factory({
        seed: `${spec.seed}:bouquet-primitive:${primitive}:${batch.typeId}:${i}`,
        position: p,
        scale: roleScale * batch.scale * compositionScaleForPrimitive(primitive) * localRng.range(0.72, primitive === 'SpikeFlower' ? 1.02 : 1.22) * specialScale * tuningScale * spikeScale,
        colorPalette: primitivePalette(spec, primitive, localRng, batch),
        openness: ['OrchidButterflyFlower', 'TrumpetThroatFlower', 'DaturaTrumpetFlower', 'CallaCurledBract'].includes(primitive) ? 0.94 : localRng.range(0.62, 0.86),
        density: ['UmbelMiniCluster', 'FullHydrangeaCloud', 'FruitPodCluster'].includes(primitive) ? 1.08 : localRng.range(0.86, 1.02),
        curvature: ['SpikeFlower', 'FoliageGrassBranch', 'CallaCurledBract'].includes(primitive) ? 0.86 : 0.42,
        role: primitiveRoleForPlanItem(batch)
      });
      primitiveGroup.name = `${primitive}:${batch.cn}`;
      orientPrimitiveGroup(primitiveGroup, primitive, p, theta, localRng, batch.placement);
      primitiveGroup.updateMatrix();
      const flowerId = `${spec.flowerPlan.id}:${batch.typeId}:${primitive}:${i}`;
      flowerRecords.push({
        flowerId,
        placementOrder: flowerRecords.length,
        matrix: primitiveGroup.matrix.toArray(),
        colors: objectColorSignature(primitiveGroup)
      });
      stems.push(createFlowerStem(spec, `stem:${flowerId}`, batch.typeId, p));
      group.add(primitiveGroup);
      if (primitive === 'SpikeFlower') group.add(buildSpikeStemConnector(spec, primitiveGroup, localRng));
    }
  });

  const foliageFactory = floraPrimitiveFactories.FoliageGrassBranch;
  const foliageRng = createRng(`${spec.seed}:primitive-foliage-accents`);
  const foliageAccentRatio = spec.dateLabel === '2026-07-16' ? 0.024 : 0.08;
  const foliageCount = Math.max(spec.dateLabel === '2026-07-16' ? 3 : 6, Math.floor(count * foliageAccentRatio * spec.theme.wildness));
  for (let i = 0; i < foliageCount; i += 1) {
    const { p, theta } = placementPoint(spec, foliageRng, i % 4 === 0 ? 'spray' : i % 2 === 0 ? 'outer' : 'mixed');
    p.y -= foliageRng.range(0.18, 0.42);
    p.multiplyScalar(foliageRng.range(0.9, 1.02));
    const stemId = `legacy:${spec.seed}:foliage-grass-branch:${i}`;
    const foliage = foliageFactory({
      seed: `${spec.seed}:bouquet-foliage:${i}`,
      position: p,
      scale: spec.dateLabel === '2026-07-16' ? foliageRng.range(0.12, 0.2) : foliageRng.range(0.2, 0.32),
      colorPalette: primitivePalette(spec, 'FoliageGrassBranch', foliageRng),
      openness: 0.74,
      density: 0.92,
      curvature: 0.86,
      role: 'line',
      leafOwnership: {
        stemId,
        foliageProfile: temporaryLegacyFoliageProfile.foliageProfile,
        leafArrangement: temporaryLegacyFoliageProfile.leafArrangement
      }
    });
    orientPrimitiveGroup(foliage, 'FoliageGrassBranch', p, theta, foliageRng);
    const legacy = readTemporaryLegacyFoliage(spec, foliage, stemId);
    stems.push(legacy.stem);
    leaves.push(...legacy.leaves);
    group.add(foliage);
  }

  const confirmedFoliage = buildConfirmedFoliage({
    stems,
    seed: spec.seed,
    palette: spec.theme.leafPalette,
    density: spec.leafDensity,
    context: 'bouquet'
  });
  leaves.push(...confirmedFoliage.leaves);
  group.add(confirmedFoliage.object);

  return { object: group, flowerRecords, stems, leaves } satisfies FlowerBuildResult;
}

function placementPoint(
  spec: DailyBouquetSpec,
  rng: ReturnType<typeof createRng>,
  placement: FlowerPlanItem['placement']
) {
  const theta = rng.range(0, Math.PI * 2);
  const phiRanges: Record<FlowerPlanItem['placement'], [number, number]> = {
    center: [0.58, 1.34],
    outer: [0.36, 1.6],
    high: [0.2, 1.04],
    low: [1.02, 1.78],
    spray: [0.26, 1.7],
    mixed: [0.36, 1.66]
  };
  const radiusRanges: Record<FlowerPlanItem['placement'], [number, number]> = {
    center: [0.42, 1.18],
    outer: [0.92, 1.92],
    high: [0.74, 1.82],
    low: [0.46, 1.5],
    spray: [1.02, 2.08],
    mixed: [0.5, 1.78]
  };
  const heightRanges: Record<FlowerPlanItem['placement'], [number, number]> = {
    center: [0.86, 1.36],
    outer: [0.82, 1.5],
    high: [1.08, 1.72],
    low: [0.68, 1.18],
    spray: [0.92, 1.62],
    mixed: [0.82, 1.46]
  };
  const [phiMin, phiMax] = phiRanges[placement];
  const [radiusMin, radiusMax] = radiusRanges[placement];
  const [heightMin, heightMax] = heightRanges[placement];
  const p = bouquetPoint(spec, rng.range(radiusMin, radiusMax), rng.range(heightMin, heightMax), theta, rng.range(phiMin, phiMax));
  const radialSpread = spec.compositionTuning?.radialSpread ?? 1;
  const placementSpread = placement === 'center' ? spec.compositionTuning?.centerSpread ?? 1 : 1;
  p.x *= radialSpread * placementSpread;
  p.z *= radialSpread * placementSpread;
  const liftRanges: Record<FlowerPlanItem['placement'], [number, number]> = {
    center: [-0.18, 0.24],
    outer: [-0.24, 0.34],
    high: [0.12, 0.54],
    low: [-0.46, 0.1],
    spray: [-0.18, 0.46],
    mixed: [-0.26, 0.36]
  };
  const [liftMin, liftMax] = liftRanges[placement];
  p.y += spec.haloLift + rng.range(liftMin, liftMax);
  return { p, theta };
}

function buildFlowers(spec: DailyBouquetSpec, quality: QualityProfile) {
  const rng = createRng(`${spec.seed}:flowers`);
  const count = Math.floor(quality.flowerCount * spec.flowerDensity);
  const material = new THREE.MeshStandardMaterial({
    roughness: 0.82,
    metalness: 0.0,
    flatShading: true,
    side: THREE.DoubleSide,
    emissive: new THREE.Color(spec.theme.glow),
    emissiveIntensity: 0.08
  });
  const flowerRecords: FlowerAuditRecord[] = [];
  const stems: PlantStemInstance[] = [];
  const leaves: LeafInstanceRecord[] = [];

  const place = (
    mesh: THREE.InstancedMesh,
    localRng: ReturnType<typeof createRng>,
    itemCount: number,
    scaleBias = 1,
    colorLift = 0.1,
    placement: FlowerPlanItem['placement'] = 'mixed'
  ) => {
    for (let i = 0; i < itemCount; i += 1) {
      const { p, theta } = placementPoint(spec, localRng, placement);
      const bloom = spec.special?.bloomScale;
      const large = bloom && localRng.value() < bloom.largeBias;
      const scale = (bloom
        ? localRng.range(bloom.small, large ? bloom.large : bloom.medium)
        : localRng.range(0.46, 0.9) * (localRng.value() > 0.96 ? 1.08 : 1)) * scaleBias;
      tempObject.position.copy(p);
      tempObject.quaternion.setFromUnitVectors(up, p.clone().normalize());
      tempObject.rotateZ(localRng.range(0, Math.PI * 2));
      tempObject.rotateX(localRng.range(-0.38, 0.38));
      if (spec.special) {
        tempObject.scale.set(scale * localRng.range(0.9, 1.28), scale * localRng.range(0.56, 0.82), scale * localRng.range(0.9, 1.18));
      } else {
        tempObject.scale.set(scale * localRng.range(0.82, 1.16), scale * localRng.range(0.82, 1.12), scale * localRng.range(0.72, 1.06));
      }
      tempObject.updateMatrix();
      mesh.setMatrixAt(i, tempObject.matrix);
      mesh.setColorAt(i, tempColor.set(pickColor(spec.theme.palette, localRng.value())).lerp(new THREE.Color('#ffffff'), localRng.range(0.0, colorLift)));
      const flowerId = `${quality.renderName}:generic:${i}`;
      flowerRecords.push({
        flowerId,
        placementOrder: flowerRecords.length,
        matrix: tempObject.matrix.toArray(),
        colors: [tempColor.toArray().join(',')]
      });
      stems.push(createFlowerStem(spec, `stem:${flowerId}`, 'unresolved-render-placeholder', p));
    }
    if (mesh.instanceColor) mesh.instanceColor.needsUpdate = true;
  };

  if (quality.renderName === 'low') {
    const geometry = new THREE.IcosahedronGeometry(spec.special ? 0.066 : 0.058, 0);
    const mesh = new THREE.InstancedMesh(geometry, material, count);
    mesh.instanceMatrix.setUsage(THREE.DynamicDrawUsage);
    place(mesh, rng, count, 0.96, 0.06);
    return { object: mesh, flowerRecords, stems, leaves } satisfies FlowerBuildResult;
  }

  if (quality.renderName === 'medium') {
    const geometry = new THREE.SphereGeometry(spec.special ? 0.064 : 0.056, 16, 10);
    const mediumMaterial = material.clone();
    mediumMaterial.flatShading = false;
    mediumMaterial.transparent = true;
    mediumMaterial.opacity = 0.8;
    mediumMaterial.depthWrite = false;
    const mesh = new THREE.InstancedMesh(geometry, mediumMaterial, count);
    mesh.instanceMatrix.setUsage(THREE.DynamicDrawUsage);
    place(mesh, rng, count, 0.96, 0.1);
    return { object: mesh, flowerRecords, stems, leaves } satisfies FlowerBuildResult;
  }

  return buildPrimitiveFlowers(spec, quality);
}

type LeafShapeProfile = {
  name: string;
  width: number;
  length: number;
  edgePower: number;
  centerShift: number;
  edgeWave: number;
  cup: number;
  curl: number;
  veinPairs: number;
  veinReach: number;
};

const leafShapeProfiles: readonly LeafShapeProfile[] = [
  { name: 'soft-ovate', width: 0.124, length: 0.96, edgePower: 0.62, centerShift: 0.018, edgeWave: 0.018, cup: 0.0012, curl: 0.0014, veinPairs: 5, veinReach: 0.72 },
  { name: 'lanceolate', width: 0.073, length: 1.12, edgePower: 0.86, centerShift: -0.012, edgeWave: 0.012, cup: 0.0008, curl: -0.0016, veinPairs: 4, veinReach: 0.78 },
  { name: 'elliptic', width: 0.099, length: 1.02, edgePower: 0.48, centerShift: -0.022, edgeWave: 0.024, cup: 0.001, curl: 0.0007, veinPairs: 5, veinReach: 0.68 },
  { name: 'round-tip', width: 0.116, length: 0.78, edgePower: 0.36, centerShift: 0.026, edgeWave: 0.032, cup: 0.0014, curl: -0.0008, veinPairs: 4, veinReach: 0.66 },
  { name: 'willow', width: 0.047, length: 1.24, edgePower: 0.98, centerShift: 0.01, edgeWave: 0.014, cup: 0.0006, curl: 0.002, veinPairs: 3, veinReach: 0.8 }
];

function leafY(profile: LeafShapeProfile, t: number) {
  return THREE.MathUtils.lerp(-0.15 * profile.length, 0.13 * profile.length, t);
}

function leafT(profile: LeafShapeProfile, y: number) {
  return THREE.MathUtils.clamp((y + 0.15 * profile.length) / (0.28 * profile.length), 0, 1);
}

function leafCenterX(profile: LeafShapeProfile, t: number) {
  return profile.centerShift * Math.sin(Math.PI * t) * (0.7 + t * 0.3);
}

function leafHalfWidth(profile: LeafShapeProfile, t: number) {
  const body = Math.pow(Math.max(0, Math.sin(Math.PI * t)), profile.edgePower);
  const taperBias = 0.9 + t * 0.1;
  const edgeVariation = 1 + Math.sin(t * Math.PI * 5.0) * profile.edgeWave;
  return body * profile.width * taperBias * edgeVariation;
}

function leafSurfaceHeight(profile: LeafShapeProfile, x: number, y: number) {
  const t = leafT(profile, y);
  const center = leafCenterX(profile, t);
  const halfWidth = Math.max(leafHalfWidth(profile, t), 0.0001);
  const across = THREE.MathUtils.clamp(Math.abs(x - center) / halfWidth, 0, 1);
  const softCup = Math.pow(across, 1.8) * profile.cup;
  const flexibleCurl = Math.sin((t - 0.12) * Math.PI) * profile.curl;
  return softCup + flexibleCurl;
}

function pointToSegmentDistance(
  px: number,
  py: number,
  ax: number,
  ay: number,
  bx: number,
  by: number
) {
  const abx = bx - ax;
  const aby = by - ay;
  const lengthSq = abx * abx + aby * aby || 1;
  const amount = THREE.MathUtils.clamp(((px - ax) * abx + (py - ay) * aby) / lengthSq, 0, 1);
  return Math.hypot(px - (ax + abx * amount), py - (ay + aby * amount));
}

function leafVeinIndentation(
  profile: LeafShapeProfile,
  across: number,
  t: number,
  renderName: QualityProfile['renderName']
) {
  const mainDistance = Math.abs(across - 0.5);
  const mainInfluence = Math.exp(-Math.pow(mainDistance / 0.022, 2) * 3.2);
  const pairCount = renderName === 'low' ? Math.min(3, profile.veinPairs) : profile.veinPairs;
  let sideInfluence = 0;
  for (let index = 0; index < pairCount; index += 1) {
    const branchT = 0.23 + (index / Math.max(1, pairCount - 1)) * 0.56;
    const endT = Math.min(0.94, branchT + 0.1);
    const midT = THREE.MathUtils.lerp(branchT, endT, 0.5);
    for (const direction of [-1, 1]) {
      const midAcross = 0.5 + direction * 0.18;
      const endAcross = 0.5 + direction * profile.veinReach * 0.5;
      const firstDistance = pointToSegmentDistance(across, t, 0.5, branchT, midAcross, midT);
      const secondDistance = pointToSegmentDistance(across, t, midAcross, midT, endAcross, endT);
      const branchDistance = Math.min(firstDistance, secondDistance);
      sideInfluence = Math.max(sideInfluence, Math.exp(-Math.pow(branchDistance / 0.018, 2) * 3.4));
    }
  }
  const lengthFade = Math.pow(Math.max(0, Math.sin(Math.PI * t)), 0.32);
  const depth = renderName === 'low' ? 0.00032 : 0.0005;
  return (mainInfluence * 0.82 + sideInfluence * 0.48) * lengthFade * depth;
}

function buildLeafBladeGeometry(profile: LeafShapeProfile, renderName: QualityProfile['renderName']) {
  const lengthSegments = renderName === 'low' ? 16 : 32;
  const widthSegments = renderName === 'low' ? 10 : 20;
  const positions: number[] = [];
  const uvs: number[] = [];
  const indices: number[] = [];
  const rowSize = widthSegments + 1;

  for (let row = 0; row <= lengthSegments; row += 1) {
    const t = row / lengthSegments;
    const y = leafY(profile, t);
    const center = leafCenterX(profile, t);
    const halfWidth = leafHalfWidth(profile, t);
    for (let column = 0; column <= widthSegments; column += 1) {
      const across = column / widthSegments;
      const x = center + THREE.MathUtils.lerp(-halfWidth, halfWidth, across);
      const z = leafSurfaceHeight(profile, x, y) - leafVeinIndentation(profile, across, t, renderName);
      positions.push(x, y, z);
      uvs.push(across, t);
    }
  }

  for (let row = 0; row < lengthSegments; row += 1) {
    for (let column = 0; column < widthSegments; column += 1) {
      const a = row * rowSize + column;
      const b = a + 1;
      const c = a + rowSize;
      const d = c + 1;
      indices.push(a, b, c, b, d, c);
    }
  }

  const baseY = leafY(profile, 0);
  const rootY = baseY - 0.038 * profile.length;
  const petioleWidth = Math.min(0.0017, profile.width * 0.022);
  const petioleStart = positions.length / 3;
  positions.push(
    -petioleWidth * 0.55, rootY, leafSurfaceHeight(profile, 0, baseY),
    petioleWidth * 0.55, rootY, leafSurfaceHeight(profile, 0, baseY),
    -petioleWidth, baseY + 0.006 * profile.length, leafSurfaceHeight(profile, 0, baseY),
    petioleWidth, baseY + 0.006 * profile.length, leafSurfaceHeight(profile, 0, baseY)
  );
  uvs.push(0.48, 0, 0.52, 0, 0.48, 0.03, 0.52, 0.03);
  indices.push(
    petioleStart, petioleStart + 1, petioleStart + 2,
    petioleStart + 1, petioleStart + 3, petioleStart + 2
  );

  const geometry = new THREE.BufferGeometry();
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  geometry.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2));
  geometry.setIndex(indices);
  geometry.computeVertexNormals();
  geometry.computeBoundingSphere();
  return geometry;
}

function setLeafPose(
  object: THREE.Object3D,
  position: THREE.Vector3,
  bladeAxis: THREE.Vector3,
  desiredSurfaceNormal: THREE.Vector3
) {
  leafBladeAxis.copy(bladeAxis).normalize();
  leafBladeNormal.copy(desiredSurfaceNormal).addScaledVector(leafBladeAxis, -desiredSurfaceNormal.dot(leafBladeAxis));
  if (leafBladeNormal.lengthSq() < 0.0001) {
    leafBladeNormal.copy(up).addScaledVector(leafBladeAxis, -up.dot(leafBladeAxis));
  }
  if (leafBladeNormal.lengthSq() < 0.0001) {
    leafBladeNormal.copy(forward).addScaledVector(leafBladeAxis, -forward.dot(leafBladeAxis));
  }
  leafBladeNormal.normalize();
  leafBladeRight.crossVectors(leafBladeAxis, leafBladeNormal).normalize();
  leafBladeNormal.crossVectors(leafBladeRight, leafBladeAxis).normalize();
  leafBasis.makeBasis(leafBladeRight, leafBladeAxis, leafBladeNormal);
  object.position.copy(position);
  object.quaternion.setFromRotationMatrix(leafBasis);
}

type LeafPoseFrame = {
  stemTangent: THREE.Vector3;
  radialOutward: THREE.Vector3;
  azimuthTangent: THREE.Vector3;
  petioleDirection: THREE.Vector3;
  bladeAxis: THREE.Vector3;
  bladeNormal: THREE.Vector3;
  bladeRight: THREE.Vector3;
  pitchDegrees: number;
  rollDegrees: number;
};

function makeLeafPoseFrame(
  stemTangentInput: THREE.Vector3,
  azimuth: number,
  pitchDegrees: number,
  rollDegrees: number,
  tipDroopDegrees: number,
  axialWeight: number,
  sideBias: number,
  preferredHemisphereWeight: number
): LeafPoseFrame {
  const stemTangent = stemTangentInput.clone().normalize();
  leafReference.copy(Math.abs(stemTangent.dot(up)) > 0.9 ? worldRight : up);
  const radialBase = new THREE.Vector3().crossVectors(stemTangent, leafReference).normalize();
  const radialOutward = radialBase.clone().applyAxisAngle(stemTangent, azimuth).normalize();
  const azimuthTangent = new THREE.Vector3().crossVectors(stemTangent, radialOutward).normalize();
  const pitch = THREE.MathUtils.degToRad(pitchDegrees);
  const roll = THREE.MathUtils.degToRad(rollDegrees);
  const tipDroop = THREE.MathUtils.degToRad(tipDroopDegrees);
  const petioleDirection = radialOutward
    .clone()
    .multiplyScalar(0.86)
    .addScaledVector(stemTangent, axialWeight)
    .normalize();
  const bladeAxis = petioleDirection
    .clone()
    .applyAxisAngle(azimuthTangent, pitch)
    .addScaledVector(azimuthTangent, sideBias)
    .addScaledVector(gravityDirection, Math.sin(tipDroop) * 0.32)
    .normalize();
  const bladeNormal = new THREE.Vector3().crossVectors(azimuthTangent, bladeAxis).normalize();
  leafPreferredHemisphere
    .copy(radialOutward)
    .multiplyScalar(1 - preferredHemisphereWeight)
    .addScaledVector(stemTangent, preferredHemisphereWeight * 0.42)
    .normalize();
  if (bladeNormal.dot(leafPreferredHemisphere) < 0) bladeNormal.negate();
  bladeNormal.applyAxisAngle(bladeAxis, roll).normalize();
  const bladeRight = new THREE.Vector3().crossVectors(bladeAxis, bladeNormal).normalize();
  bladeNormal.crossVectors(bladeRight, bladeAxis).normalize();
  return { stemTangent, radialOutward, azimuthTangent, petioleDirection, bladeAxis, bladeNormal, bladeRight, pitchDegrees, rollDegrees };
}

function addDebugLine(
  group: THREE.Group,
  start: THREE.Vector3,
  end: THREE.Vector3,
  color: string,
  opacity = 1
) {
  const geometry = new THREE.BufferGeometry().setFromPoints([start, end]);
  const material = new THREE.LineBasicMaterial({ color, transparent: opacity < 1, opacity });
  group.add(new THREE.Line(geometry, material));
}

type LeafPoseDebugView = 'front' | 'side' | 'top' | 'perspective' | 'orbit';
type LeafDebugMaterialMode = 'normal' | 'monochrome' | 'silhouette' | 'front' | 'back' | 'wireframe';
type LeafDebugPrototype = 'strap' | 'lanceolate' | 'ovate' | 'palmate' | 'compound';

type LeafPoseStats = {
  leafCount: number;
  stemCount: number;
  realisticFlowerLeafCount: number;
  temporaryLegacyStemCount: number;
  beforeTotalLeafCount: number;
  afterTotalLeafCount: number;
  totalLeafDelta: number;
  stems: Array<{
    stemId: string;
    plantMemberId: string;
    foliageProfile: string;
    leafMode: 'attached';
    leafArrangement: 'alternate';
  }>;
  pitchRange: [number, number];
  rollRange: [number, number];
  meanPitch: number;
  meanRoll: number;
  nearHorizontalRatio: number;
  nearVerticalRatio: number;
};

function stemPointAt(t: number, xOffset = 0) {
  return new THREE.Vector3(
    xOffset + Math.sin(t * Math.PI * 1.18 - 0.35) * 0.13,
    THREE.MathUtils.lerp(-0.92, 0.92, t),
    Math.cos(t * Math.PI * 1.04 + 0.5) * 0.08
  );
}

function stemTangentAt(t: number, xOffset = 0) {
  const delta = 0.015;
  return stemPointAt(Math.min(1, t + delta), xOffset).sub(stemPointAt(Math.max(0, t - delta), xOffset)).normalize();
}

function makeDebugStem(xOffset = 0) {
  const curve = new THREE.CatmullRomCurve3(Array.from({ length: 12 }, (_, index) => stemPointAt(index / 11, xOffset)));
  const geometry = new THREE.TubeGeometry(curve, 42, 0.018, 10, false);
  const material = new THREE.MeshStandardMaterial({ color: '#375b34', roughness: 0.82 });
  return new THREE.Mesh(geometry, material);
}

function makeDebugLeafMaterial(mode: LeafDebugMaterialMode) {
  if (mode === 'normal') return new THREE.MeshNormalMaterial({ side: THREE.DoubleSide });
  const color = mode === 'silhouette' ? '#2f7f38' : '#5fa45f';
  return new THREE.MeshStandardMaterial({
    color,
    roughness: 0.78,
    metalness: 0,
    side: mode === 'front' ? THREE.FrontSide : mode === 'back' ? THREE.BackSide : THREE.DoubleSide,
    wireframe: mode === 'wireframe'
  });
}

function addLocalRib(group: THREE.Group, start: THREE.Vector3, end: THREE.Vector3, radius: number, material: THREE.Material) {
  const direction = end.clone().sub(start);
  const length = direction.length();
  if (length <= 0.0001) return;
  const rib = new THREE.Mesh(new THREE.CylinderGeometry(radius, radius, length, 6), material);
  rib.position.copy(start).add(end).multiplyScalar(0.5);
  rib.quaternion.setFromUnitVectors(up, direction.normalize());
  group.add(rib);
}

function makeGridLeafGeometry(
  length: number,
  widthAt: (t: number) => number,
  options: {
    lengthSegments?: number;
    widthSegments?: number;
    centerX?: (t: number) => number;
    surfaceZ?: (signedAcross: number, t: number) => number;
  } = {}
) {
  const lengthSegments = options.lengthSegments ?? 24;
  const widthSegments = options.widthSegments ?? 14;
  const positions: number[] = [];
  const indices: number[] = [];
  const rowSize = widthSegments + 1;
  for (let row = 0; row <= lengthSegments; row += 1) {
    const t = row / lengthSegments;
    const y = length * t;
    const halfWidth = Math.max(0.0001, widthAt(t));
    const centerX = options.centerX?.(t) ?? 0;
    for (let column = 0; column <= widthSegments; column += 1) {
      const across = column / widthSegments;
      const signed = across * 2 - 1;
      const edgeFade = 1 - Math.abs(signed);
      const z = (options.surfaceZ?.(signed, t) ?? 0) * Math.max(0.18, edgeFade);
      positions.push(centerX + signed * halfWidth, y, z);
    }
  }
  for (let row = 0; row < lengthSegments; row += 1) {
    for (let column = 0; column < widthSegments; column += 1) {
      const a = row * rowSize + column;
      const b = a + 1;
      const c = a + rowSize;
      const d = c + 1;
      indices.push(a, b, c, b, d, c);
    }
  }
  const geometry = new THREE.BufferGeometry();
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  geometry.setIndex(indices);
  geometry.computeVertexNormals();
  geometry.computeBoundingSphere();
  return geometry;
}

function makeVeinedBlade(
  geometry: THREE.BufferGeometry,
  material: THREE.Material,
  length: number,
  sideVeins: Array<[number, number, number, number]> = [],
  parallelXs: number[] = []
) {
  const group = new THREE.Group();
  group.add(new THREE.Mesh(geometry, material));
  addLocalRib(group, new THREE.Vector3(0, 0.012, -0.006), new THREE.Vector3(0, length * 0.96, -0.006), 0.0032, material);
  sideVeins.forEach(([startY, endX, endY, radius]) => {
    addLocalRib(group, new THREE.Vector3(0, startY, -0.0055), new THREE.Vector3(endX, endY, -0.0055), radius, material);
    addLocalRib(group, new THREE.Vector3(0, startY, -0.0055), new THREE.Vector3(-endX, endY, -0.0055), radius, material);
  });
  parallelXs.forEach((x) => {
    addLocalRib(group, new THREE.Vector3(x, length * 0.07, -0.0048), new THREE.Vector3(x * 0.55, length * 0.92, -0.0048), 0.0017, material);
  });
  return group;
}

function makeBladeOnly(geometry: THREE.BufferGeometry, material: THREE.Material) {
  const group = new THREE.Group();
  group.add(new THREE.Mesh(geometry, material));
  return group;
}

function makeStrapLeafGeometry(length: number) {
  const lengthSegments = 32;
  const widthSegments = 14;
  const positions: number[] = [];
  const indices: number[] = [];
  const rowSize = widthSegments + 1;
  for (let row = 0; row <= lengthSegments; row += 1) {
    const t = row / lengthSegments;
    let halfWidth = 0;
    if (t < 0.18) {
      halfWidth = THREE.MathUtils.lerp(0.028, 0.041, THREE.MathUtils.smoothstep(t, 0, 0.18));
    } else if (t < 0.7) {
      const middle = THREE.MathUtils.smoothstep(t, 0.18, 0.7);
      halfWidth = THREE.MathUtils.lerp(0.041, 0.0375, middle) + Math.sin(t * Math.PI * 2.2) * 0.0009;
    } else {
      const tip = THREE.MathUtils.smoothstep(t, 0.7, 1);
      halfWidth = THREE.MathUtils.lerp(0.0375, 0.0045, tip ** 1.15);
    }
    const asymmetry = Math.sin(t * Math.PI * 1.35 + 0.42);
    const leftHalfWidth = halfWidth * (1 + asymmetry * 0.032);
    const rightHalfWidth = halfWidth * (1 - asymmetry * 0.024);
    const tipBias = THREE.MathUtils.smoothstep(t, 0.58, 1);
    const centerX = Math.sin(t * Math.PI * 0.92) * 0.0045 + tipBias * 0.0085;
    const tipDroop = -0.012 * THREE.MathUtils.smoothstep(t, 0.72, 1) ** 2;
    for (let column = 0; column <= widthSegments; column += 1) {
      const across = column / widthSegments;
      const signedAcross = across * 2 - 1;
      const x = centerX + THREE.MathUtils.lerp(-leftHalfWidth, rightHalfWidth, across);
      const fold = -0.0036 * (1 - Math.abs(signedAcross)) * (0.48 + Math.sin(t * Math.PI) * 0.52);
      const shallowTwist = signedAcross * Math.sin(t * Math.PI * 0.82) * 0.0016;
      positions.push(x, length * t, fold + shallowTwist + tipDroop);
    }
  }
  for (let row = 0; row < lengthSegments; row += 1) {
    for (let column = 0; column < widthSegments; column += 1) {
      const a = row * rowSize + column;
      const b = a + 1;
      const c = a + rowSize;
      const d = c + 1;
      indices.push(a, b, c, b, d, c);
    }
  }
  const geometry = new THREE.BufferGeometry();
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  geometry.setIndex(indices);
  geometry.computeVertexNormals();
  geometry.computeBoundingSphere();
  return geometry;
}

function makeStrapLeaf(material: THREE.Material, showVeins: boolean) {
  const length = 0.64;
  const geometry = makeStrapLeafGeometry(length);
  return showVeins ? makeVeinedBlade(geometry, material, length, [], [-0.018, -0.009, 0.009, 0.018]) : makeBladeOnly(geometry, material);
}

function makeLanceolateLeaf(material: THREE.Material, showVeins: boolean) {
  const length = 0.58;
  const geometry = makeGridLeafGeometry(length, (t) => {
    const peak = Math.exp(-(((t - 0.42) / 0.27) ** 2));
    const baseTaper = THREE.MathUtils.smoothstep(t, 0.02, 0.18);
    const tipTaper = 1 - THREE.MathUtils.smoothstep(t, 0.72, 1);
    return 0.075 * peak * baseTaper * Math.max(0.02, tipTaper);
  }, {
    surfaceZ: (x, t) => -0.005 * Math.abs(x) - 0.012 * Math.max(0, t - 0.68) ** 2
  });
  return showVeins ? makeVeinedBlade(geometry, material, length, [
    [0.15, 0.045, 0.24, 0.0017],
    [0.24, 0.056, 0.34, 0.0017],
    [0.34, 0.045, 0.44, 0.0015]
  ]) : makeBladeOnly(geometry, material);
}

function makeOvateLeaf(material: THREE.Material, showVeins: boolean) {
  const length = 0.5;
  const geometry = makeGridLeafGeometry(length, (t) => {
    const body = Math.sin(Math.PI * Math.max(0, Math.min(1, t))) ** 0.56;
    const basalShoulder = 1 + 0.28 * Math.exp(-(((t - 0.28) / 0.16) ** 2));
    const serration = 1 + 0.055 * Math.sin(t * Math.PI * 18);
    const baseTaper = THREE.MathUtils.smoothstep(t, 0, 0.1);
    return 0.11 * body * basalShoulder * serration * Math.max(0.25, baseTaper);
  }, {
    centerX: (t) => Math.sin(t * Math.PI) * 0.01,
    surfaceZ: (x, t) => -0.006 * Math.abs(x) - 0.007 * Math.sin(t * Math.PI)
  });
  return showVeins ? makeVeinedBlade(geometry, material, length, [
    [0.12, 0.062, 0.21, 0.002],
    [0.19, 0.086, 0.31, 0.002],
    [0.27, 0.076, 0.4, 0.0018],
    [0.35, 0.05, 0.455, 0.0015]
  ]) : makeBladeOnly(geometry, material);
}

function subdivideLeafSurface(geometry: THREE.BufferGeometry) {
  const source = geometry.index ? geometry.toNonIndexed() : geometry;
  const sourcePositions = source.getAttribute('position');
  const positions: number[] = [];
  const a = new THREE.Vector3();
  const b = new THREE.Vector3();
  const c = new THREE.Vector3();
  const ab = new THREE.Vector3();
  const bc = new THREE.Vector3();
  const ca = new THREE.Vector3();
  const pushTriangle = (v0: THREE.Vector3, v1: THREE.Vector3, v2: THREE.Vector3) => {
    positions.push(v0.x, v0.y, v0.z, v1.x, v1.y, v1.z, v2.x, v2.y, v2.z);
  };
  for (let index = 0; index < sourcePositions.count; index += 3) {
    a.fromBufferAttribute(sourcePositions, index);
    b.fromBufferAttribute(sourcePositions, index + 1);
    c.fromBufferAttribute(sourcePositions, index + 2);
    ab.copy(a).add(b).multiplyScalar(0.5);
    bc.copy(b).add(c).multiplyScalar(0.5);
    ca.copy(c).add(a).multiplyScalar(0.5);
    pushTriangle(a, ab, ca);
    pushTriangle(ab, b, bc);
    pushTriangle(ca, bc, c);
    pushTriangle(ab, bc, ca);
  }
  if (source !== geometry) source.dispose();
  geometry.dispose();
  const subdivided = new THREE.BufferGeometry();
  subdivided.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  return subdivided;
}

function makePalmateLeafGeometry() {
  const outlineControls = [
    new THREE.Vector3(0.004, 0.014, 0),
    new THREE.Vector3(0.058, 0.083, 0),
    new THREE.Vector3(0.128, 0.146, 0),
    new THREE.Vector3(0.204, 0.21, 0),
    new THREE.Vector3(0.222, 0.232, 0),
    new THREE.Vector3(0.204, 0.252, 0),
    new THREE.Vector3(0.166, 0.268, 0),
    new THREE.Vector3(0.116, 0.29, 0),
    new THREE.Vector3(0.132, 0.342, 0),
    new THREE.Vector3(0.156, 0.386, 0),
    new THREE.Vector3(0.17, 0.408, 0),
    new THREE.Vector3(0.15, 0.417, 0),
    new THREE.Vector3(0.118, 0.4, 0),
    new THREE.Vector3(0.076, 0.368, 0),
    new THREE.Vector3(0.066, 0.426, 0),
    new THREE.Vector3(0.038, 0.505, 0),
    new THREE.Vector3(0.009, 0.535, 0),
    new THREE.Vector3(-0.028, 0.508, 0),
    new THREE.Vector3(-0.06, 0.424, 0),
    new THREE.Vector3(-0.076, 0.36, 0),
    new THREE.Vector3(-0.116, 0.394, 0),
    new THREE.Vector3(-0.148, 0.414, 0),
    new THREE.Vector3(-0.162, 0.396, 0),
    new THREE.Vector3(-0.15, 0.376, 0),
    new THREE.Vector3(-0.13, 0.33, 0),
    new THREE.Vector3(-0.108, 0.278, 0),
    new THREE.Vector3(-0.158, 0.262, 0),
    new THREE.Vector3(-0.198, 0.244, 0),
    new THREE.Vector3(-0.214, 0.224, 0),
    new THREE.Vector3(-0.194, 0.202, 0),
    new THREE.Vector3(-0.128, 0.144, 0),
    new THREE.Vector3(-0.058, 0.082, 0)
  ];
  const outlineCurve = new THREE.CatmullRomCurve3(outlineControls, true, 'centripetal', 0.38);
  const outlinePoints = outlineCurve.getPoints(72);
  const outline = new THREE.Shape();
  outline.moveTo(outlinePoints[0].x, outlinePoints[0].y);
  outlinePoints.slice(1).forEach((point) => outline.lineTo(point.x, point.y));
  outline.closePath();
  const flatGeometry = new THREE.ShapeGeometry(outline, 8);
  const geometry = subdivideLeafSurface(flatGeometry);
  const position = geometry.getAttribute('position');
  for (let index = 0; index < position.count; index += 1) {
    const x = position.getX(index);
    const y = position.getY(index);
    const palmDistance = Math.hypot(x, (y - 0.12) * 0.84);
    const palmCup = -0.0024 * Math.exp(-((x / 0.16) ** 2 + ((y - 0.19) / 0.2) ** 2));
    const lobeBend = -0.0055 * THREE.MathUtils.smoothstep(palmDistance, 0.13, 0.43) ** 2;
    const quietAsymmetry = x * 0.007 * Math.sin(Math.min(1, y / 0.54) * Math.PI);
    position.setZ(index, palmCup + lobeBend + quietAsymmetry);
  }
  position.needsUpdate = true;
  geometry.computeVertexNormals();
  geometry.computeBoundingSphere();
  return geometry;
}

function makePalmateLeaf(material: THREE.Material, showVeins: boolean) {
  const geometry = makePalmateLeafGeometry();
  const group = new THREE.Group();
  group.add(new THREE.Mesh(geometry, material));
  if (showVeins) {
    [
      new THREE.Vector3(0, 0.51, -0.006),
      new THREE.Vector3(0.16, 0.42, -0.006),
      new THREE.Vector3(0.2, 0.25, -0.006),
      new THREE.Vector3(-0.16, 0.42, -0.006),
      new THREE.Vector3(-0.2, 0.25, -0.006)
    ].forEach((tip) => addLocalRib(group, new THREE.Vector3(0, 0.02, -0.006), tip, 0.0025, material));
  }
  return group;
}

function makeCompoundLeaf(material: THREE.Material, showVeins: boolean) {
  const group = new THREE.Group();
  const length = 0.62;
  addLocalRib(group, new THREE.Vector3(0, 0.02, -0.003), new THREE.Vector3(0, length, -0.003), 0.004, material);
  const leafletGeometry = makeGridLeafGeometry(0.18, (t) => Math.sin(Math.PI * t) ** 0.78 * 0.028, {
    lengthSegments: 12,
    widthSegments: 8,
    surfaceZ: (x, t) => -0.0025 * Math.abs(x) - 0.006 * Math.max(0, t - 0.65) ** 2
  });
  const leafletYs = [0.12, 0.22, 0.32, 0.42, 0.51];
  leafletYs.forEach((y, index) => {
    const spread = 0.12 + index * 0.01;
    for (const side of [-1, 1]) {
      if (index === leafletYs.length - 1 && side === -1) continue;
      const leaflet = new THREE.Group();
      const mesh = new THREE.Mesh(leafletGeometry, material);
      leaflet.add(mesh);
      if (showVeins) addLocalRib(leaflet, new THREE.Vector3(0, 0.02, -0.004), new THREE.Vector3(0, 0.165, -0.004), 0.0015, material);
      leaflet.position.set(side * 0.018, y, 0);
      leaflet.rotation.z = side * -(0.72 - index * 0.08);
      leaflet.scale.setScalar(index === leafletYs.length - 1 ? 1.12 : 1);
      group.add(leaflet);
      addLocalRib(group, new THREE.Vector3(0, y, -0.003), new THREE.Vector3(side * spread * 0.38, y + 0.055, -0.003), 0.0018, material);
    }
  });
  const terminal = new THREE.Group();
  terminal.add(new THREE.Mesh(leafletGeometry, material));
  if (showVeins) addLocalRib(terminal, new THREE.Vector3(0, 0.02, -0.004), new THREE.Vector3(0, 0.165, -0.004), 0.0015, material);
  terminal.position.set(0, 0.53, 0);
  terminal.scale.setScalar(1.18);
  group.add(terminal);
  return group;
}

function makeDebugLeafPrototype(prototype: LeafDebugPrototype, material: THREE.Material, showVeins: boolean) {
  if (prototype === 'strap') return makeStrapLeaf(material, showVeins);
  if (prototype === 'lanceolate') return makeLanceolateLeaf(material, showVeins);
  if (prototype === 'ovate') return makeOvateLeaf(material, showVeins);
  if (prototype === 'palmate') return makePalmateLeaf(material, showVeins);
  return makeCompoundLeaf(material, showVeins);
}

function roundStat(value: number) {
  return Math.round(value * 1000) / 1000;
}

function summarizeLeafPoseStats(
  poses: LeafPoseFrame[],
  stems: LeafPoseStats['stems'],
  beforeTotalLeafCount: number
): LeafPoseStats {
  const pitches = poses.map((pose) => pose.pitchDegrees);
  const rolls = poses.map((pose) => pose.rollDegrees);
  const normalUps = poses.map((pose) => Math.abs(pose.bladeNormal.dot(up)));
  return {
    leafCount: poses.length,
    stemCount: stems.length,
    realisticFlowerLeafCount: 0,
    temporaryLegacyStemCount: stems.length,
    beforeTotalLeafCount,
    afterTotalLeafCount: poses.length,
    totalLeafDelta: poses.length - beforeTotalLeafCount,
    stems,
    pitchRange: [roundStat(Math.min(...pitches)), roundStat(Math.max(...pitches))],
    rollRange: [roundStat(Math.min(...rolls)), roundStat(Math.max(...rolls))],
    meanPitch: roundStat(pitches.reduce((sum, value) => sum + value, 0) / pitches.length),
    meanRoll: roundStat(rolls.reduce((sum, value) => sum + value, 0) / rolls.length),
    nearHorizontalRatio: roundStat(normalUps.filter((value) => value > Math.cos(THREE.MathUtils.degToRad(25))).length / poses.length),
    nearVerticalRatio: roundStat(normalUps.filter((value) => value < Math.sin(THREE.MathUtils.degToRad(25))).length / poses.length)
  };
}

export function createLeafPoseDebugScene(
  canvas: HTMLCanvasElement,
  view: LeafPoseDebugView = 'front',
  materialMode: LeafDebugMaterialMode = 'monochrome',
  options: { prototype?: LeafDebugPrototype; comparison?: boolean } = {}
) {
  const scene = new THREE.Scene();
  scene.background = new THREE.Color('#10170f');
  const camera = new THREE.PerspectiveCamera(42, 1, 0.1, 100);
  const renderer = new THREE.WebGLRenderer({ canvas, antialias: true, powerPreference: 'high-performance' });
  renderer.outputColorSpace = THREE.SRGBColorSpace;
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  scene.add(new THREE.AmbientLight('#fff7e4', 1.1));
  const key = new THREE.DirectionalLight('#fff0c8', 1.8);
  key.position.set(2.4, 4.2, 3.4);
  scene.add(key);

  const group = new THREE.Group();
  scene.add(group);

  const leafMaterial = makeDebugLeafMaterial(materialMode);
  const showLeafVeins = materialMode !== 'silhouette';
  const axisLength = 0.2;
  const poses: LeafPoseFrame[] = [];
  const allPrototypes: LeafDebugPrototype[] = ['strap', 'lanceolate', 'ovate', 'palmate', 'compound'];
  const selectedPrototype = options.prototype ?? 'ovate';
  const specimens = options.comparison
    ? allPrototypes.map((prototype, index) => ({ prototype, xOffset: (index - 2) * 0.72 }))
    : [{ prototype: selectedPrototype, xOffset: 0 }];
  const stemMetadata: LeafPoseStats['stems'] = [];
  const pitchByNode = [-32, 42, -14, 16, 51, -25, 28, 6];
  const rollByNode = [-24, 18, 72, -32, 12, 29, -18, 44];
  specimens.forEach(({ prototype, xOffset }, stemIndex) => {
    const stemId = `debug:temporary-legacy:${stemIndex}`;
    stemMetadata.push({
      stemId,
      plantMemberId: `debug-only:${prototype}`,
      foliageProfile: `temporary-legacy:${prototype}`,
      leafMode: 'attached',
      leafArrangement: 'alternate'
    });
    group.add(makeDebugStem(xOffset));
    const nodeTs = options.comparison ? [0.2, 0.46, 0.72] : [0.08, 0.2, 0.32, 0.44, 0.56, 0.68, 0.8, 0.92];
    nodeTs.forEach((t, index) => {
      const node = stemPointAt(t, xOffset);
      const stemTangent = stemTangentAt(t, xOffset);
      const azimuth = index * 2.399963 + stemIndex * 0.41;
      const ageTrend = 1 - t;
      const pitch = pitchByNode[index];
      const roll = rollByNode[index];
      const pose = makeLeafPoseFrame(
        stemTangent,
        azimuth,
        pitch,
        roll,
        THREE.MathUtils.lerp(20, 5, t),
        THREE.MathUtils.lerp(-0.22, 0.24, t) + 0.04,
        Math.sin(index * 1.3 + stemIndex) * 0.16,
        THREE.MathUtils.lerp(0.12, 0.34, ageTrend)
      );
      poses.push(pose);
      const base = node.clone().addScaledVector(pose.petioleDirection, 0.22);
      const leaf = makeDebugLeafPrototype(prototype, leafMaterial, showLeafVeins);
      leaf.name = `${stemId}:leaf:${index}:${prototype}`;
      leaf.userData.stemId = stemId;
      leaf.userData.foliageProfile = `temporary-legacy:${prototype}`;
      leaf.userData.leafArrangement = 'alternate';
      setLeafPose(leaf, base, pose.bladeAxis, pose.bladeNormal);
      leaf.scale.setScalar(options.comparison ? 0.78 : 1.08);
      group.add(leaf);

      const right = new THREE.Vector3(1, 0, 0).applyQuaternion(leaf.quaternion).normalize();
      const axis = new THREE.Vector3(0, 1, 0).applyQuaternion(leaf.quaternion).normalize();
      const normal = new THREE.Vector3(0, 0, 1).applyQuaternion(leaf.quaternion).normalize();
      addDebugLine(group, node, base, '#f5c542', 0.9);
      addDebugLine(group, node, node.clone().addScaledVector(pose.stemTangent, axisLength * 0.9), '#ff9a3c', 0.85);
      addDebugLine(group, base, base.clone().addScaledVector(right, axisLength), '#ff4b4b');
      addDebugLine(group, base, base.clone().addScaledVector(axis, axisLength * 1.15), '#5cff5c');
      addDebugLine(group, base, base.clone().addScaledVector(normal, axisLength), '#55a7ff');
    });
  });

  const worldUpX = options.comparison ? -2.0 : -0.62;
  addDebugLine(group, new THREE.Vector3(worldUpX, -0.95, -0.62), new THREE.Vector3(worldUpX, -0.55, -0.62), '#7de8ff');
  const beforeTotalLeafCount = options.comparison ? allPrototypes.length * 3 : 10;
  const stats = summarizeLeafPoseStats(poses, stemMetadata, beforeTotalLeafCount);
  (window as Window & { __leafPoseDebugStats?: LeafPoseStats }).__leafPoseDebugStats = stats;

  const target = new THREE.Vector3(0, -0.04, 0);
  function setCamera() {
    const width = window.innerWidth;
    const height = window.innerHeight;
    camera.aspect = width / height;
    camera.updateProjectionMatrix();
    renderer.setSize(width, height, false);
    const distanceScale = options.comparison ? 1.55 : 1;
    if (view === 'top') camera.position.set(0.001, 4.25 * distanceScale, 0.001);
    else if (view === 'side') camera.position.set(3.2 * distanceScale, 1.05, 0);
    else if (view === 'perspective' || view === 'orbit') camera.position.set(2.4 * distanceScale, 1.9, 3.2 * distanceScale);
    else camera.position.set(0, 1.05, 3.35 * distanceScale);
    camera.lookAt(target);
  }

  let animationId = 0;
  const render = () => {
    animationId = window.requestAnimationFrame(render);
    if (view === 'orbit') {
      group.rotation.y += 0.008;
    }
    renderer.render(scene, camera);
  };
  window.addEventListener('resize', setCamera);
  setCamera();

  return {
    stats,
    start() {
      render();
    },
    stop() {
      window.cancelAnimationFrame(animationId);
      window.removeEventListener('resize', setCamera);
      renderer.dispose();
    }
  };
}

function buildStemBundle(spec: DailyBouquetSpec, stems: readonly PlantStemInstance[]) {
  const positions: number[] = [];
  const colors: number[] = [];
  const stem = new THREE.Color(spec.theme.stem);
  const flowerStems = stems.filter((plantStem) => plantStem.source === 'realistic-flower');
  const visibleStemCount = Math.min(
    flowerStems.length,
    Math.floor(18 * (spec.special?.shape.stemVisibility ?? 1))
  );
  const visibleStems = Array.from({ length: visibleStemCount }, (_, index) => {
    if (visibleStemCount <= 1) return flowerStems[0];
    return flowerStems[Math.round(index * (flowerStems.length - 1) / (visibleStemCount - 1))];
  });
  visibleStems.forEach((plantStem) => {
    const tint = (hashString(`${spec.seed}:stem-color:${plantStem.stemId}`) % 2400) / 10000;
    const color = stem.clone().lerp(new THREE.Color('#d5d09b'), tint);
    plantStem.curvePoints.forEach((point, pointIndex) => {
      if (pointIndex === plantStem.curvePoints.length - 1) return;
      const next = plantStem.curvePoints[pointIndex + 1];
      positions.push(point.x, point.y, point.z, next.x, next.y, next.z);
      colors.push(color.r, color.g, color.b, color.r, color.g, color.b);
    });
  });

  const geometry = new THREE.BufferGeometry();
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  geometry.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3));
  const material = new THREE.LineBasicMaterial({
    vertexColors: true,
    transparent: true,
    opacity: spec.dateLabel === '2026-07-16' ? 0.1 : 0.16
  });
  const lines = new THREE.LineSegments(geometry, material);

  const bandGeometry = new THREE.CylinderGeometry(0.13, 0.11, 0.08, 20, 1, true);
  const bandMaterial = new THREE.MeshStandardMaterial({
    color: '#b8b08d',
    roughness: 0.86,
    metalness: 0,
    transparent: true,
    opacity: 0.07,
    side: THREE.DoubleSide
  });
  const band = new THREE.Mesh(bandGeometry, bandMaterial);
  band.position.y = -1.0;
  const group = new THREE.Group();
  group.add(lines, band);
  return group;
}

function buildSpecialBabyBreath(spec: DailyBouquetSpec, quality: QualityProfile) {
  const rng = createRng(`${spec.seed}:baby-breath`);
  const count = Math.floor(quality.particleCount * 0.22);
  const positions: number[] = [];
  const colors: number[] = [];
  for (let i = 0; i < count; i += 1) {
    const theta = rng.range(0, Math.PI * 2);
    const phi = rng.range(0.18, 1.42);
    const spray = rng.value() ** 0.18;
    const p = bouquetPoint(spec, rng.range(1.0, 2.2) * spray, rng.range(1.04, 1.78), theta, phi);
    p.y += spec.haloLift + rng.range(-0.08, 0.58);
    if (rng.value() > 0.78) p.x -= rng.range(0.1, 0.52);
    positions.push(p.x, p.y, p.z);
    const color = new THREE.Color(rng.value() > 0.82 ? '#dbe9ff' : '#fffcef');
    colors.push(color.r, color.g, color.b);
  }
  const geometry = new THREE.BufferGeometry();
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  geometry.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3));
  const material = new THREE.PointsMaterial({
    size: 0.018,
    map: makeRadialTexture() ?? undefined,
    vertexColors: true,
    transparent: true,
    opacity: 0.82,
    blending: THREE.AdditiveBlending,
    depthWrite: false,
    sizeAttenuation: true
  });
  return new THREE.Points(geometry, material);
}

function buildSpecialWrapping(spec: DailyBouquetSpec) {
  if (!spec.special) return new THREE.Group();
  const { wrapping } = spec.special;
  const group = new THREE.Group();
  const material = new THREE.MeshStandardMaterial({
    color: wrapping.color,
    emissive: new THREE.Color(wrapping.edgeColor),
    emissiveIntensity: 0.03,
    roughness: 0.58,
    metalness: 0,
    transparent: true,
    opacity: wrapping.opacity,
    side: THREE.DoubleSide,
    depthWrite: false
  });
  const edgeMaterial = new THREE.LineBasicMaterial({
    color: wrapping.edgeColor,
    transparent: true,
    opacity: 0.16,
    depthWrite: false
  });
  for (let i = 0; i < 7; i += 1) {
    const angle = (i / 7) * Math.PI * 2 + (i % 2) * 0.16;
    const width = 0.54 + (i % 3) * 0.08;
    const height = 1.78 + (i % 2) * 0.34;
    const shape = new THREE.Shape();
    shape.moveTo(-width * 0.22, -1.1);
    shape.lineTo(width, height - 1.14);
    shape.lineTo(-width * 0.78, height - 1.32);
    shape.lineTo(-width * 0.22, -1.1);
    const geometry = new THREE.ShapeGeometry(shape);
    const panel = new THREE.Mesh(geometry, material);
    panel.position.set(Math.cos(angle) * 0.22, -0.1, Math.sin(angle) * 0.22);
    panel.rotation.set(-0.12 + (i % 2) * 0.08, angle - Math.PI / 2, 0.12 - (i % 3) * 0.08);
    group.add(panel);

    const points = shape.getPoints();
    const edgeGeometry = new THREE.BufferGeometry().setFromPoints(points);
    const edge = new THREE.Line(edgeGeometry, edgeMaterial);
    edge.position.copy(panel.position);
    edge.rotation.copy(panel.rotation);
    group.add(edge);
  }

  const ribbonGeometry = new THREE.TorusGeometry(0.2, 0.012, 8, 42);
  const ribbonMaterial = new THREE.MeshStandardMaterial({
    color: wrapping.ribbonColor,
    roughness: 0.74,
    transparent: true,
    opacity: 0.58
  });
  const ribbon = new THREE.Mesh(ribbonGeometry, ribbonMaterial);
  ribbon.position.y = -0.92;
  ribbon.rotation.x = Math.PI / 2;
  group.add(ribbon);
  return group;
}

function buildSpecialDustRings(spec: DailyBouquetSpec, quality: QualityProfile) {
  if (!spec.special) return new THREE.Group();
  const rng = createRng(`${spec.seed}:dust-rings`);
  const group = new THREE.Group();
  group.userData.spin = 0.018;
  const count = quality.renderName === 'low' ? 680 : quality.renderName === 'medium' ? 980 : 1320;
  const positions: number[] = [];
  const colors: number[] = [];
  for (let i = 0; i < count; i += 1) {
    const ring = rng.value() > 0.58 ? 1 : 0;
    const theta = rng.range(0, Math.PI * 2);
    const radius = rng.range(ring ? 1.38 : 0.82, ring ? 2.34 : 1.52);
    positions.push(
      Math.cos(theta) * radius * rng.range(0.88, 1.12),
      rng.range(-0.18, 0.5) + Math.sin(theta * 2.0) * 0.05,
      Math.sin(theta) * radius * rng.range(0.24, 0.4)
    );
    const color = new THREE.Color(pickColor(spec.special.cosmic.dustColors, rng.value()));
    colors.push(color.r, color.g, color.b);
  }
  const geometry = new THREE.BufferGeometry();
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  geometry.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3));
  const material = new THREE.PointsMaterial({
    size: 0.012,
    map: makeRadialTexture() ?? undefined,
    vertexColors: true,
    transparent: true,
    opacity: 0.52,
    blending: THREE.AdditiveBlending,
    depthWrite: false,
    sizeAttenuation: true
  });
  const points = new THREE.Points(geometry, material);
  points.rotation.set(0.42, 0.1, -0.08);
  group.add(points);
  return group;
}

function buildSpecialCosmicLayer(spec: DailyBouquetSpec, quality: QualityProfile) {
  const group = new THREE.Group();
  if (!spec.special) return group;
  const rng = createRng(`${spec.seed}:cosmic-sky`);
  const starCount = quality.renderName === 'low' ? 260 : quality.renderName === 'medium' ? 420 : 620;
  const positions: number[] = [];
  const colors: number[] = [];
  for (let i = 0; i < starCount; i += 1) {
    const depth = rng.range(-10.8, -8.4);
    positions.push(rng.range(-7.5, 7.5), rng.range(-4.3, 4.3), depth);
    const color = new THREE.Color(pickColor(spec.special.cosmic.starColors, rng.value()));
    colors.push(color.r, color.g, color.b);
  }
  const starGeometry = new THREE.BufferGeometry();
  starGeometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  starGeometry.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3));
  const stars = new THREE.Points(
    starGeometry,
    new THREE.PointsMaterial({
      size: 0.018,
      map: makeRadialTexture() ?? undefined,
      vertexColors: true,
      transparent: true,
      opacity: 0.62,
      blending: THREE.AdditiveBlending,
      depthWrite: false,
      sizeAttenuation: true
    })
  );
  group.add(stars);

  const galaxyTexture = new THREE.TextureLoader().load(withBasePath(spec.special.hubbleImagePath));
  galaxyTexture.colorSpace = THREE.SRGBColorSpace;
  const galaxyScale = spec.special.cosmic.galaxyScale ?? 1;
  const galaxyPosition = spec.special.cosmic.galaxyPosition ?? [0.42, 0.62, -9.1];
  const galaxyMaterial = spec.special.cosmic.galaxyAlphaMap
    ? new THREE.ShaderMaterial({
        uniforms: {
          map: { value: galaxyTexture },
          tint: { value: new THREE.Color(spec.special.cosmic.galaxyTint) },
          opacity: { value: spec.special.cosmic.galaxyOpacity ?? 0.34 }
        },
        vertexShader: `
          varying vec2 vUv;
          void main() {
            vUv = uv;
            gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
          }
        `,
        fragmentShader: `
          uniform sampler2D map;
          uniform vec3 tint;
          uniform float opacity;
          varying vec2 vUv;

          void main() {
            vec4 tex = texture2D(map, vUv);
            float luminance = dot(tex.rgb, vec3(0.299, 0.587, 0.114));
            float alpha = smoothstep(0.045, 0.42, luminance) * opacity;
            vec3 lifted = pow(tex.rgb, vec3(0.52)) * tint * 1.7;
            gl_FragColor = vec4(lifted, alpha);
          }
        `,
        transparent: true,
        depthWrite: false,
        depthTest: spec.special.cosmic.galaxyDepthTest ?? true
      })
    : new THREE.MeshBasicMaterial({
        map: galaxyTexture,
        color: spec.special.cosmic.galaxyTint,
        transparent: true,
        opacity: spec.special.cosmic.galaxyOpacity ?? 0.34,
        blending: THREE.AdditiveBlending,
        depthWrite: false,
        depthTest: spec.special.cosmic.galaxyDepthTest ?? true
      });
  const galaxy = new THREE.Mesh(
    new THREE.PlaneGeometry(4.5 * galaxyScale, 4.4 * galaxyScale),
    galaxyMaterial
  );
  galaxy.position.set(galaxyPosition[0], galaxyPosition[1], galaxyPosition[2]);
  galaxy.rotation.z = spec.special.cosmic.galaxyRotation ?? -0.2;
  group.add(galaxy);

  const core = new THREE.Mesh(
    new THREE.CircleGeometry(spec.special.cosmic.coreRadius ?? 0.72, 48),
    new THREE.MeshBasicMaterial({
      color: spec.special.cosmic.warmCore,
      transparent: true,
      opacity: spec.special.cosmic.coreOpacity ?? 0.16,
      blending: THREE.AdditiveBlending,
      depthWrite: false,
      depthTest: spec.special.cosmic.galaxyDepthTest ?? true
    })
  );
  core.position.set(galaxyPosition[0] - 0.18, galaxyPosition[1] - 0.04, galaxyPosition[2] + 0.05);
  group.add(core);
  return group;
}

export class BouquetScene {
  readonly renderer: THREE.WebGLRenderer;
  readonly scene = new THREE.Scene();
  readonly camera = new THREE.PerspectiveCamera(38, 1, 0.1, 100);
  readonly bouquet = new THREE.Group();
  readonly cosmicLayer = new THREE.Group();

  private readonly clock = new THREE.Clock();
  private readonly canvas: HTMLCanvasElement;
  private spec: DailyBouquetSpec;
  private quality: QualityProfile;
  private frameInterval: number;
  private accumulator = 0;
  private isPaused = false;
  private isDragging = false;
  private dragX = 0;
  private dragY = 0;
  private routeSpeed: number;
  private routeDirection: 1 | -1 = 1;
  private routeMode: CameraRouteMode = 'orbit';
  private routeTime = 0;
  private routePausedByDrag = false;
  private cameraYaw = 0;
  private targetCameraYaw = 0;
  private cameraPitch = 0.38;
  private targetCameraPitch = 0.38;
  private baseCameraPitch = 0.38;
  private pitchAmplitude = 0;
  private yawAmplitude = 0;
  private distanceAmplitude = 0;
  private targetYAmplitude = 0;
  private zoomOffset = 0;
  private cameraDistance = 5.36;
  private baseCameraDistance = 5.36;
  private targetCameraDistance = 5.36;
  private presentationTargetX = 0;
  private cameraTargetY = 0.7;
  private baseCameraTargetY = 0.7;
  private targetCameraTargetY = 0.7;
  private floorMaterial?: THREE.MeshBasicMaterial;
  private animationId = 0;
  private debugFrameCount = 0;
  private debugFps = 0;
  private debugSampleAt = performance.now();
  private flowerRecords: FlowerAuditRecord[] = [];
  private ownershipAudit: LeafOwnershipAudit = {
    realisticFlowerLeafCount: 0,
    temporaryLegacyStemCount: 0,
    beforeLooseLeafCount: 0,
    beforeTotalLeafCount: 0,
    afterTotalLeafCount: 0,
    totalLeafDelta: 0,
    orphanLeafCount: 0,
    mixedProfileStemCount: 0,
    mixedArrangementStemCount: 0,
    unresolvedGeneratedLeafCount: 0,
    detachedLeafNodeCount: 0,
    flowerCount: 0,
    flowerRecords: []
  };

  constructor(canvas: HTMLCanvasElement, spec: DailyBouquetSpec, quality: QualityProfile) {
    this.canvas = canvas;
    this.spec = spec;
    this.quality = quality;
    this.routeSpeed = spec.rotationSpeed;
    this.frameInterval = 1 / quality.targetFps;
    this.renderer = new THREE.WebGLRenderer({
      canvas,
      antialias: true,
      alpha: false,
      powerPreference: quality.renderName === 'low' ? 'low-power' : 'high-performance'
    });
    this.renderer.outputColorSpace = THREE.SRGBColorSpace;
    this.renderer.setClearColor(spec.theme.background);
    this.renderer.setPixelRatio(Math.min(window.devicePixelRatio, quality.pixelRatio));
    this.scene.fog = new THREE.Fog(spec.theme.background, 4.8, 9.2);
    this.cameraYaw = (hashString(spec.seed) % 628) / 100;
    this.targetCameraYaw = this.cameraYaw;
    this.scene.add(this.camera);
    this.camera.add(this.cosmicLayer);
    this.scene.add(this.bouquet);
    this.addLights();
    this.addStage();
    this.rebuild(spec, quality);
    this.bindPointer();
    this.resize();
  }

  rebuild(spec: DailyBouquetSpec, quality: QualityProfile) {
    this.spec = spec;
    this.quality = quality;
    this.frameInterval = 1 / quality.targetFps;
    this.renderer.setClearColor(spec.theme.background);
    this.renderer.setPixelRatio(Math.min(window.devicePixelRatio, quality.pixelRatio));
    this.scene.fog = new THREE.Fog(spec.theme.background, 4.8, 9.2);
    if (this.floorMaterial) {
      this.floorMaterial.color.set(spec.theme.floor);
    }

    while (this.bouquet.children.length) {
      const child = this.bouquet.children.pop();
      if (child) this.disposeObject(child);
    }
    while (this.cosmicLayer.children.length) {
      const child = this.cosmicLayer.children.pop();
      if (child) this.disposeObject(child);
    }

    this.bouquet.rotation.set(0, (hashString(spec.seed) % 628) / 100, 0);
    if (spec.special) {
      this.cosmicLayer.add(buildSpecialCosmicLayer(spec, quality));
    }
    const flowers = buildFlowers(spec, quality);
    this.flowerRecords = flowers.flowerRecords;
    const beforeLooseLeafCount = Math.floor(quality.leafCount * spec.leafDensity * (spec.special ? 0.68 : 1));
    const validation = validateLeafOwnership(flowers.stems, flowers.leaves);
    const temporaryLegacyStemCount = flowers.stems.filter((stem) => stem.source === 'temporary-legacy').length;
    const realisticStemIds = new Set(
      flowers.stems.filter((stem) => stem.source === 'realistic-flower').map((stem) => stem.stemId)
    );
    const realisticFlowerLeafCount = flowers.leaves.filter((leaf) => realisticStemIds.has(leaf.stemId)).length;
    const beforeTotalLeafCount = beforeLooseLeafCount + flowers.leaves.length;
    this.ownershipAudit = {
      realisticFlowerLeafCount,
      temporaryLegacyStemCount,
      beforeLooseLeafCount,
      beforeTotalLeafCount,
      afterTotalLeafCount: flowers.leaves.length,
      totalLeafDelta: flowers.leaves.length - beforeTotalLeafCount,
      ...validation,
      flowerCount: flowers.flowerRecords.length,
      flowerRecords: flowers.flowerRecords
    };
    this.bouquet.add(
      buildSpecialDustRings(spec, quality),
      buildStemBundle(spec, flowers.stems),
      buildSpecialWrapping(spec),
      buildBranches(spec, quality),
      buildOuterLines(spec, quality),
      flowers.object,
      buildParticles(spec, quality),
      ...(spec.special ? [buildSpecialBabyBreath(spec, quality)] : [])
    );
  }

  setStaticCameraView(view: 'front' | 'side' | 'top') {
    this.routePausedByDrag = true;
    this.routeTime = 0;
    this.cameraYaw = view === 'side' ? Math.PI / 2 : 0;
    this.targetCameraYaw = this.cameraYaw;
    this.cameraPitch = view === 'top' ? 1.32 : view === 'side' ? 0.38 : 0.34;
    this.targetCameraPitch = this.cameraPitch;
    this.updateCamera(emptyRouteOffsets);
    this.renderer.render(this.scene, this.camera);
  }

  start() {
    this.clock.start();
    const animate = () => {
      this.animationId = window.requestAnimationFrame(animate);
      const delta = Math.min(this.clock.getDelta(), 0.1);
      if (this.quality.targetFps >= 58) {
        this.accumulator = 0;
        this.tick(delta);
        return;
      }
      this.accumulator += delta;
      if (this.accumulator < this.frameInterval) return;
      const step = this.accumulator;
      this.accumulator %= this.frameInterval;
      this.tick(step);
    };
    animate();
  }

  stop() {
    window.cancelAnimationFrame(this.animationId);
  }

  togglePause() {
    this.isPaused = !this.isPaused;
    return this.isPaused;
  }

  setRotationSettings(settings: {
    speed?: number;
    direction?: 1 | -1;
    pitch?: number;
    mode?: CameraRouteMode;
    pitchAmplitude?: number;
    yawAmplitude?: number;
    distanceAmplitude?: number;
    targetYAmplitude?: number;
  }) {
    if (settings.speed !== undefined) {
      this.routeSpeed = THREE.MathUtils.clamp(settings.speed, 0.006, 0.16);
    }
    if (settings.direction !== undefined) {
      this.routeDirection = settings.direction;
    }
    if (settings.pitch !== undefined) {
      this.baseCameraPitch = THREE.MathUtils.clamp(settings.pitch, minCameraPitch, maxCameraPitch);
      this.targetCameraPitch = this.baseCameraPitch;
    }
    if (settings.mode !== undefined) {
      this.routeMode = settings.mode;
      this.routeTime = 0;
      this.routePausedByDrag = false;
    }
    if (settings.pitchAmplitude !== undefined) {
      this.pitchAmplitude = THREE.MathUtils.clamp(settings.pitchAmplitude, 0, 0.42);
    }
    if (settings.yawAmplitude !== undefined) {
      this.yawAmplitude = THREE.MathUtils.clamp(settings.yawAmplitude, 0, 0.58);
    }
    if (settings.distanceAmplitude !== undefined) {
      this.distanceAmplitude = THREE.MathUtils.clamp(settings.distanceAmplitude, 0, 0.62);
    }
    if (settings.targetYAmplitude !== undefined) {
      this.targetYAmplitude = THREE.MathUtils.clamp(settings.targetYAmplitude, 0, 0.2);
    }
  }

  resize() {
    const width = Math.max(1, this.canvas.clientWidth || window.innerWidth);
    const height = Math.max(1, this.canvas.clientHeight || window.innerHeight);
    const ratio = width / height;
    const phone = width < 720;
    const wide = ratio > 1.65;
    this.camera.aspect = width / height;
    this.camera.fov = phone ? 42 : wide ? 32 : 34;
    this.baseCameraDistance = phone ? 6.9 : wide ? 6.15 : 6.45;
    this.targetCameraDistance = this.baseCameraDistance + this.zoomOffset;
    this.cameraDistance = this.targetCameraDistance;
    this.baseCameraTargetY = phone ? 0.66 : wide ? 0.74 : 0.7;
    this.targetCameraTargetY = this.baseCameraTargetY;
    this.cameraTargetY = this.baseCameraTargetY;
    this.updateCamera(emptyRouteOffsets);
    this.camera.updateProjectionMatrix();
    this.renderer.setSize(width, height, false);
  }

  private tick(delta: number) {
    let routeOffsets = emptyRouteOffsets;
    if (!this.isPaused && !this.isDragging && !this.routePausedByDrag) {
      this.routeTime += delta * this.routeDirection;
      routeOffsets = this.routeOffsets();
      this.targetCameraYaw += this.routeSpeed * this.routeDirection * this.routePulse() * delta;
      this.targetCameraPitch = THREE.MathUtils.clamp(this.baseCameraPitch + routeOffsets.pitch, minCameraPitch, maxCameraPitch);
      this.targetCameraDistance = this.baseCameraDistance + this.zoomOffset + routeOffsets.distance;
      this.targetCameraTargetY = this.baseCameraTargetY + routeOffsets.targetY;
    }
    this.cameraYaw += (this.targetCameraYaw - this.cameraYaw) * 0.1;
    this.cameraPitch += (this.targetCameraPitch - this.cameraPitch) * 0.1;
    this.cameraDistance += (this.targetCameraDistance - this.cameraDistance) * 0.08;
    this.cameraTargetY += (this.targetCameraTargetY - this.cameraTargetY) * 0.08;
    this.bouquet.position.y = 0.06 + Math.sin(performance.now() * 0.00025) * 0.026;
    if (this.spec.special) {
      const elapsed = performance.now() * 0.001;
      this.bouquet.children.forEach((child) => {
        if (child.userData.spin) child.rotation.y = elapsed * child.userData.spin;
      });
    }
    this.updateCamera(routeOffsets);
    this.renderer.render(this.scene, this.camera);
    this.updateDebugFps();
  }

  private updateDebugFps() {
    this.debugFrameCount += 1;
    const now = performance.now();
    const elapsed = now - this.debugSampleAt;
    if (elapsed < 500) return;
    this.debugFps = Math.round((this.debugFrameCount * 1000) / elapsed);
    this.debugFrameCount = 0;
    this.debugSampleAt = now;
  }

  getDebugStats() {
    const size = this.renderer.getSize(new THREE.Vector2());
    const heap = (performance as Performance & {
      memory?: {
        usedJSHeapSize: number;
        totalJSHeapSize: number;
        jsHeapSizeLimit: number;
      };
    }).memory;

    return {
      fps: this.debugFps,
      targetFps: this.quality.targetFps,
      density: this.quality.densityName,
      render: this.quality.renderName,
      pixelRatio: this.renderer.getPixelRatio(),
      canvasWidth: Math.round(size.x),
      canvasHeight: Math.round(size.y),
      geometries: this.renderer.info.memory.geometries,
      textures: this.renderer.info.memory.textures,
      calls: this.renderer.info.render.calls,
      triangles: this.renderer.info.render.triangles,
      points: this.renderer.info.render.points,
      lines: this.renderer.info.render.lines,
      jsHeapUsedMb: heap ? Math.round(heap.usedJSHeapSize / 1024 / 1024) : null,
      jsHeapTotalMb: heap ? Math.round(heap.totalJSHeapSize / 1024 / 1024) : null,
      jsHeapLimitMb: heap ? Math.round(heap.jsHeapSizeLimit / 1024 / 1024) : null,
      leafOwnership: this.ownershipAudit,
      flowerAudit: {
        flowerCount: this.flowerRecords.length,
        records: this.flowerRecords
      }
    };
  }

  private updateCamera(routeOffsets: CameraRouteOffsets) {
    const yaw = this.cameraYaw + routeOffsets.yaw;
    const pitch = THREE.MathUtils.clamp(this.cameraPitch, minCameraPitch, maxCameraPitch);
    const distance = THREE.MathUtils.clamp(this.cameraDistance, 3.2, 8.7);
    const target = new THREE.Vector3(this.presentationTargetX, this.cameraTargetY, 0);
    const horizontal = Math.cos(pitch) * distance;

    this.camera.position.set(
      Math.sin(yaw) * horizontal,
      target.y + Math.sin(pitch) * distance,
      Math.cos(yaw) * horizontal
    );
    this.camera.lookAt(target);
  }

  private routePulse() {
    if (this.routeMode === 'near-far') {
      return 0.78 + Math.sin(this.routeTime * 0.82) * 0.2;
    }
    if (this.routeMode === 'figure-eight') {
      return 0.54 + Math.sin(this.routeTime * 1.05) * 0.16 + Math.sin(this.routeTime * 0.37) * 0.12;
    }
    if (this.routeMode === 'high-arc') {
      return 0.74 + Math.sin(this.routeTime * 0.48) * 0.12;
    }
    if (this.routeMode === 'low-arc') {
      return 0.64 + Math.cos(this.routeTime * 0.54) * 0.12;
    }
    return 1;
  }

  private routeOffsets(): CameraRouteOffsets {
    if (this.routeMode === 'orbit') return emptyRouteOffsets;

    if (this.routeMode === 'figure-eight') {
      return {
        yaw: Math.sin(this.routeTime * 0.55) * this.yawAmplitude,
        pitch:
          Math.sin(this.routeTime * 0.42) * this.pitchAmplitude +
          Math.sin(this.routeTime * 0.9 + Math.PI / 3) * this.pitchAmplitude * 0.42,
        distance: Math.cos(this.routeTime * 0.38) * this.distanceAmplitude,
        targetY: Math.sin(this.routeTime * 0.31) * this.targetYAmplitude
      };
    }

    if (this.routeMode === 'near-far') {
      return {
        yaw: Math.sin(this.routeTime * 0.34) * this.yawAmplitude,
        pitch: Math.sin(this.routeTime * 0.5) * this.pitchAmplitude,
        distance: Math.sin(this.routeTime * 0.72) * this.distanceAmplitude,
        targetY: Math.cos(this.routeTime * 0.44) * this.targetYAmplitude
      };
    }

    if (this.routeMode === 'high-arc') {
      return {
        yaw: Math.sin(this.routeTime * 0.28) * this.yawAmplitude,
        pitch: Math.sin(this.routeTime * 0.36) * this.pitchAmplitude,
        distance: Math.cos(this.routeTime * 0.26) * this.distanceAmplitude,
        targetY: Math.sin(this.routeTime * 0.22) * this.targetYAmplitude
      };
    }

    return {
      yaw: Math.sin(this.routeTime * 0.38) * this.yawAmplitude,
      pitch: Math.sin(this.routeTime * 0.44) * this.pitchAmplitude,
      distance: Math.cos(this.routeTime * 0.48) * this.distanceAmplitude,
      targetY: Math.sin(this.routeTime * 0.3) * this.targetYAmplitude
    };
  }

  private addLights() {
    const ambient = new THREE.AmbientLight('#fff7e4', 0.96);
    const hemi = new THREE.HemisphereLight('#f4fff2', '#17402d', 0.72);
    const key = new THREE.DirectionalLight('#fff0c8', 1.7);
    key.position.set(2.4, 4.2, 3.4);
    const fill = new THREE.DirectionalLight('#eadcff', 0.82);
    fill.position.set(-3.2, 2.6, 2.2);
    const rim = new THREE.DirectionalLight('#9cf7d2', 0.72);
    rim.position.set(-4, 2.2, -3.5);
    this.scene.add(ambient, hemi, key, fill, rim);
  }

  private addStage() {
    const floorGeometry = new THREE.CircleGeometry(1.16, 80);
    const floorMaterial = new THREE.MeshBasicMaterial({
      color: this.spec.theme.floor,
      transparent: true,
      opacity: 0.035,
      depthWrite: false
    });
    this.floorMaterial = floorMaterial;
    const floor = new THREE.Mesh(floorGeometry, floorMaterial);
    floor.rotation.x = -Math.PI / 2;
    floor.position.y = -1.38;
    this.scene.add(floor);
  }

  private bindPointer() {
    this.canvas.addEventListener('pointerdown', (event) => {
      this.isDragging = true;
      this.routePausedByDrag = true;
      this.canvas.setPointerCapture(event.pointerId);
      this.dragX = event.clientX;
      this.dragY = event.clientY;
      this.targetCameraYaw = this.cameraYaw;
      this.targetCameraPitch = this.cameraPitch;
      this.targetCameraDistance = this.cameraDistance;
      this.targetCameraTargetY = this.cameraTargetY;
    });

    this.canvas.addEventListener('pointermove', (event) => {
      if (!this.isDragging) return;
      const dx = event.clientX - this.dragX;
      const dy = event.clientY - this.dragY;
      this.dragX = event.clientX;
      this.dragY = event.clientY;
      this.targetCameraYaw -= dx * 0.008;
      this.targetCameraPitch = THREE.MathUtils.clamp(
        this.targetCameraPitch + dy * 0.0058,
        minCameraPitch,
        maxCameraPitch
      );
      this.baseCameraPitch = this.targetCameraPitch;
    });

    const release = (event: PointerEvent) => {
      this.isDragging = false;
      if (this.canvas.hasPointerCapture(event.pointerId)) {
        this.canvas.releasePointerCapture(event.pointerId);
      }
    };
    this.canvas.addEventListener('pointerup', release);
    this.canvas.addEventListener('pointercancel', release);
  }

  setZoomOffset(offset: number) {
    this.zoomOffset = THREE.MathUtils.clamp(offset, minZoomOffset, maxZoomOffset);
    this.targetCameraDistance = this.baseCameraDistance + this.zoomOffset;
    return this.zoomOffset;
  }

  setClockLayout(active: boolean) {
    this.presentationTargetX = active ? 1.08 : 0;
    this.updateCamera(emptyRouteOffsets);
  }

  zoomBy(delta: number) {
    return this.setZoomOffset(this.zoomOffset + delta);
  }

  getZoomOffset() {
    return this.zoomOffset;
  }

  private disposeObject(object: THREE.Object3D) {
    object.traverse((node) => {
      const mesh = node as THREE.Mesh;
      if (mesh.geometry) mesh.geometry.dispose();
      const material = mesh.material as THREE.Material | THREE.Material[] | undefined;
      const disposeMaterial = (item: THREE.Material) => {
        const mapped = item as THREE.Material & { map?: THREE.Texture };
        if (mapped.map) mapped.map.dispose();
        item.dispose();
      };
      if (Array.isArray(material)) {
        material.forEach(disposeMaterial);
      } else if (material) {
        disposeMaterial(material);
      }
    });
  }
}
